  create policy "Enable insert for authenticated users only"
  on "public"."fanatic_answers"
  as permissive
  for insert
  to authenticated
with check (true);



  create policy "Enable users to view their own data only"
  on "public"."fanatic_answers"
  as permissive
  for select
  to authenticated
using ((( SELECT auth.uid() AS uid) = profile_id));



  create policy "Enable read access for all users"
  on "public"."fanatic_game_config"
  as permissive
  for select
  to public
using (true);



  create policy "Enable read access for all users"
  on "public"."fanatic_games"
  as permissive
  for select
  to public
using (true);



  create policy "Enable read access for all users"
  on "public"."fanatic_riddles"
  as permissive
  for select
  to public
using (true);



