  on "public"."product_catalog"
  as permissive
  for select
  to public
using (true);



  create policy "Enable read access for all users"
  on "public"."product_pricing"
  as permissive
  for select
  to public
using (true);



  create policy "Enable read access for all users"
  on "public"."profiles"
  as permissive
  for select
  to public
using (true);



  create policy "Enable read access for all users"
