using ((( SELECT auth.uid() AS uid) = profile_id));



  create policy "Enable insert for users based on user_id"
  on "public"."thunder_conversations"
  as permissive
  for insert
  to public
with check ((( SELECT auth.uid() AS uid) = profile_id));



  create policy "Enable users to view their own data only"
  on "public"."thunder_conversations"
  as permissive
  for select
  to authenticated
using ((( SELECT auth.uid() AS uid) = profile_id));


CREATE TRIGGER on_fanatic_answer_change AFTER INSERT OR UPDATE OF answer ON public.fanatic_games FOR EACH ROW EXECUTE FUNCTION public.trigger_generate_fanatic_embedding();

CREATE TRIGGER on_product_change AFTER INSERT OR UPDATE OF name, description, product_details ON public.product_catalog FOR EACH ROW EXECUTE FUNCTION public.trigger_generate_product_embedding();

CREATE TRIGGER trg_delete_expired_conversations AFTER INSERT ON public.thunder_conversations FOR EACH ROW EXECUTE FUNCTION public.trigger_delete_expired_conversations();

CREATE TRIGGER trg_create_profile AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.trigger_create_profile();


